// AUTO-GENERATED — do not edit manually
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
const __dirname = path.dirname(fileURLToPath(import.meta.url));

const icons = {
  "icon-192.png": "",
  "icon-512.png": "",
  "icon-512-maskable.png": "",
  "apple-touch-icon.png": "",
};

const pub = path.join(__dirname, "public");
let count = 0;
for (const [file, b64] of Object.entries(icons)) {
  const dest = path.join(pub, file);
  fs.writeFileSync(dest, Buffer.from(b64, "base64"));
  const kb = (b64.length * 3 / 4 / 1024).toFixed(1);
  console.log(`  ✓  ${file.padEnd(26)} (${kb} KB)`);
  count++;
}

// remove old placeholder
const ph = path.join(pub, "COPY-ICONS-README.txt");
if (fs.existsSync(ph)) { fs.unlinkSync(ph); console.log("  ✓  Removed placeholder"); }

console.log(`\nAll ${count} icons written to public/ — run: npm run dev\n`);
